INSERT OR REPLACE INTO SiteContent (key, zh, en) VALUES ('hero_title', '烟台富宁电子有限公司', 'Yantai Funing Electronics Co., Ltd.');
INSERT OR REPLACE INTO SiteContent (key, zh, en) VALUES ('hero_subtitle', '专业电子制造服务商', 'Professional Electronics Manufacturing Services');
INSERT OR REPLACE INTO SiteContent (key, zh, en) VALUES ('hero_description', '专注PCB制造、SMT贴片、电子组装及OEM/ODM服务，为全球客户提供高品质电子制造解决方案。', 'Specializing in PCB manufacturing, SMT assembly, electronics assembly, and OEM/ODM services, delivering high-quality electronics manufacturing solutions to global customers.');
INSERT OR REPLACE INTO SiteContent (key, zh, en) VALUES ('hero_cta', '了解更多', 'Learn More');
INSERT OR REPLACE INTO SiteContent (key, zh, en) VALUES ('hero_cta2', '联系我们', 'Contact Us');
INSERT OR REPLACE INTO SiteContent (key, zh, en) VALUES ('about_tag', '关于我们', 'About Us');
INSERT OR REPLACE INTO SiteContent (key, zh, en) VALUES ('about_title', '深耕电子制造，铸就卓越品质', 'Excellence in Electronics Manufacturing');
INSERT OR REPLACE INTO SiteContent (key, zh, en) VALUES ('about_p1', '烟台富宁电子有限公司成立于2008年，坐落于美丽的滨海城市——山东烟台。公司专注于印制电路板（PCB）制造、表面贴装技术（SMT）加工、电子组件组装及整机制造，是一家集研发、生产、销售于一体的综合性电子制造企业。', 'Founded in 2008, Yantai Funing Electronics Co., Ltd. is located in the beautiful coastal city of Yantai, Shandong Province. The company specializes in printed circuit board (PCB) manufacturing, surface mount technology (SMT) processing, electronic component assembly, and整机 manufacturing, serving as a comprehensive electronics manufacturing enterprise integrating R&D, production, and sales.');
INSERT OR REPLACE INTO SiteContent (key, zh, en) VALUES ('about_p2', '经过十余年的发展，富宁电子已建成现代化标准厂房超过20,000平方米，拥有多条全自动SMT产线、波峰焊产线及精密检测设备。公司年产能达到PCB 50万平方米、SMT贴片10亿点，产品广泛应用于消费电子、通信设备、工业控制、汽车电子、医疗器械等领域。', 'After more than a decade of development, Funing Electronics has built a modern standardized factory covering over 20,000 square meters, equipped with multiple fully automated SMT production lines, wave soldering lines, and precision inspection equipment. The company''s annual capacity reaches 500,000 square meters of PCB and 1 billion SMT placement points, with products widely used in consumer electronics, communication equipment, industrial control, automotive electronics, and medical devices.');
INSERT OR REPLACE INTO SiteContent (key, zh, en) VALUES ('about_p3', '我们始终秉持"质量为本、客户至上、持续创新"的经营理念，致力于成为全球电子制造领域值得信赖的合作伙伴。', 'We always adhere to the business philosophy of "Quality First, Customer Supreme, Continuous Innovation," committed to becoming a trusted partner in the global electronics manufacturing industry.');
