INSERT OR REPLACE INTO SiteContent (key, zh, en) VALUES ('products_tag', '产品中心', 'Products');
INSERT OR REPLACE INTO SiteContent (key, zh, en) VALUES ('products_title', '一站式电子制造解决方案', 'One-Stop Electronics Manufacturing Solutions');
INSERT OR REPLACE INTO SiteContent (key, zh, en) VALUES ('products_subtitle', '从设计到交付，为您提供全流程电子制造服务', 'From design to delivery, providing full-process electronics manufacturing services');
INSERT OR REPLACE INTO SiteContent (key, zh, en) VALUES ('prod_pcb_title', 'PCB制造', 'PCB Manufacturing');
INSERT OR REPLACE INTO SiteContent (key, zh, en) VALUES ('prod_pcb_desc', '高精度多层印制电路板制造，支持1-32层板，涵盖FR-4、铝基板、高TG材料等多种基材，最小线宽线距3mil，满足高密度互连（HDI）需求。', 'High-precision multi-layer PCB manufacturing, supporting 1-32 layer boards with FR-4, aluminum base, high-TG materials, and more. Minimum trace width/space of 3mil, meeting HDI (High Density Interconnect) requirements.');
INSERT OR REPLACE INTO SiteContent (key, zh, en) VALUES ('prod_smt_title', 'SMT贴片', 'SMT Assembly');
INSERT OR REPLACE INTO SiteContent (key, zh, en) VALUES ('prod_smt_desc', '全自动高速SMT贴片加工，配备YAMAHA、松下等品牌贴片机，支持01005-50组件封装，BGA/CSP等高精度贴装，满足最小批量及大批量生产需求。', 'Fully automated high-speed SMT processing with YAMAHA and Panasonic placement machines. Supporting 01005-50 component packages, BGA/CSP high-precision mounting for both small batch and mass production.');
INSERT OR REPLACE INTO SiteContent (key, zh, en) VALUES ('prod_pca_title', 'PCBA组装', 'PCBA Assembly');
INSERT OR REPLACE INTO SiteContent (key, zh, en) VALUES ('prod_pca_desc', '提供PCB组装、波峰焊、选择性焊接等全流程组装服务。支持DIP插件、线束加工、整机组装及测试，具备完善的质量管控体系。', 'Full-process assembly services including PCB assembly, wave soldering, selective soldering. Supporting DIP insertion, cable harness processing, whole machine assembly and testing with a comprehensive quality control system.');
INSERT OR REPLACE INTO SiteContent (key, zh, en) VALUES ('prod_oem_title', 'OEM/ODM服务', 'OEM/ODM Services');
INSERT OR REPLACE INTO SiteContent (key, zh, en) VALUES ('prod_oem_desc', '提供从产品设计、原理图绘制、PCB Layout到批量生产的全流程OEM/ODM服务，拥有经验丰富的研发工程团队，可快速响应客户定制化需求。', 'End-to-end OEM/ODM services from product design, schematic drawing, PCB layout to mass production. An experienced R&D engineering team enables rapid response to customized customer needs.');
INSERT OR REPLACE INTO SiteContent (key, zh, en) VALUES ('prod_box_title', '整机制造', 'Box Build');
INSERT OR REPLACE INTO SiteContent (key, zh, en) VALUES ('prod_box_desc', '提供电子产品整机组装、外壳定制、包装设计等一站式服务。支持从小批量试产到大批量稳定交付，完善的供应链管理确保交期可控。', 'One-stop services for electronic product assembly, enclosure customization, and packaging design. Supporting small batch trial production to large-scale stable delivery with supply chain management ensuring on-time delivery.');
INSERT OR REPLACE INTO SiteContent (key, zh, en) VALUES ('prod_test_title', '测试服务', 'Testing Services');
INSERT OR REPLACE INTO SiteContent (key, zh, en) VALUES ('prod_test_desc', '配备AOI自动光学检测、X-Ray检测、ICT在线测试、FCT功能测试等先进检测设备，确保每一件产品都经过严格的质量验证。', 'Equipped with AOI automatic optical inspection, X-Ray inspection, ICT online testing, FCT functional testing and other advanced inspection equipment to ensure every product undergoes rigorous quality verification.');
