INSERT OR REPLACE INTO SiteContent (key, zh, en) VALUES ('q_iatf', 'IATF 16949', 'IATF 16949');
INSERT OR REPLACE INTO SiteContent (key, zh, en) VALUES ('q_iatf_desc', '汽车行业质量管理体系认证，满足汽车电子严苛要求', 'Automotive Industry Quality Management certification for stringent automotive electronics');
INSERT OR REPLACE INTO SiteContent (key, zh, en) VALUES ('q_ul', 'UL认证', 'UL Certification');
INSERT OR REPLACE INTO SiteContent (key, zh, en) VALUES ('q_ul_desc', '产品安全认证，确保产品符合国际安全标准', 'Product safety certification ensuring compliance with international safety standards');
INSERT OR REPLACE INTO SiteContent (key, zh, en) VALUES ('quality_p1', '富宁电子建立了完善的质量管理体系，从原材料进料检验（IQC）、生产过程控制（IPQC）、出货检验（OQC）到可靠性测试，实施全面质量控制。公司配备先进的检测设备和完善的质量追溯系统，确保产品全生命周期的质量可追溯。', 'Funing Electronics has established a comprehensive quality management system, implementing total quality control from incoming material inspection (IQC), in-process quality control (IPQC), outgoing quality control (OQC) to reliability testing. The company is equipped with advanced inspection equipment and a complete quality traceability system to ensure product quality traceability throughout the lifecycle.');
INSERT OR REPLACE INTO SiteContent (key, zh, en) VALUES ('quality_p2', '我们严格执行来料检验标准，对所有原材料进行100%检验或抽检；生产过程中实施SPC统计过程控制，关键工序配备CPK能力分析；出货前进行全面的AOI、X-Ray、ICT及功能测试，确保交付给客户的每一件产品都符合最高质量标准。', 'We strictly enforce incoming inspection standards, conducting 100% inspection or sampling of all raw materials. During production, SPC statistical process control is implemented with CPK capability analysis at critical processes. Before shipment, comprehensive AOI, X-Ray, ICT and functional testing is performed to ensure every product delivered meets the highest quality standards.');
