INSERT OR REPLACE INTO SiteContent (key, zh, en) VALUES ('quality_step3', '炉后AOI检测', 'Post-Reflow AOI Inspection');
INSERT OR REPLACE INTO SiteContent (key, zh, en) VALUES ('quality_step4', 'X-Ray透视检查', 'X-Ray Examination');
