INSERT INTO NewsArticle (date, titleZh, titleEn, summaryZh, summaryEn, imageUrl, "order") VALUES ('2026-06-10', '富宁电子荣获"2026年度山东省电子信息行业优秀企业"称号', 'Funing Electronics Awarded "2026 Shandong Electronic Information Industry Outstanding Enterprise"', '近日，山东省电子信息行业协会公布了2026年度行业评选结果，烟台富宁电子有限公司凭借卓越的制造能力和优质的服务水平，荣获"年度优秀企业"荣誉称号。', 'The Shandong Electronic Information Industry Association announced the 2026 industry selection results. Yantai Funing Electronics Co., Ltd. was honored with the "Outstanding Enterprise" title for its excellent manufacturing capabilities and high-quality service.', NULL, 1);
INSERT INTO NewsArticle (date, titleZh, titleEn, summaryZh, summaryEn, imageUrl, "order") VALUES ('2026-05-20', '公司第三条全自动SMT产线正式投产运行', 'Third Fully Automated SMT Production Line Officially Put into Operation', '为满足日益增长的市场需求，富宁电子投资建设的第三条全自动高速SMT产线已于5月正式投产运行，新增产能较原有产线提升40%。', 'To meet growing market demand, Funing Electronics'' third fully automated high-speed SMT production line began operation in May. The new capacity increases production by 40% over existing lines.', NULL, 2);
INSERT INTO NewsArticle (date, titleZh, titleEn, summaryZh, summaryEn, imageUrl, "order") VALUES ('2026-04-15', '富宁电子通过IATF 16949汽车行业质量体系认证', 'Funing Electronics Achieves IATF 16949 Automotive Quality Certification', '经过近一年的体系建设与审核，富宁电子顺利通过IATF 16949:2016汽车行业质量管理体系认证，标志着公司在汽车电子制造领域迈入新阶段。', 'After nearly a year of system development and auditing, Funing Electronics successfully passed the IATF 16949:2016 automotive quality management system certification.', NULL, 3);
